SELECT id, date, ticker, blogger, sentiment_score as sentimentScore, horizon, strategy, created_at as createdAt, updated_at as updatedAt
FROM blogger_sentiments
WHERE ticker = #{ticker}
AND date = #{date}
ORDER BY blogger

